<?php
namespace App\Domain\Media;use App\Models\MediaAsset;use Illuminate\Database\Eloquent\Model;use Illuminate\Support\Facades\DB;use InvalidArgumentException;
final class MediaAssetService {public function attach(Model $mediable,array $attributes):MediaAsset{if(!$mediable->exists||!method_exists($mediable,'mediaAssets'))throw new InvalidArgumentException('Invalid mediable.');$data=$this->validate($attributes);return DB::transaction(function()use($mediable,$data){$this->lockMediable($mediable);if($data['is_primary'])$mediable->mediaAssetsOfType($data['asset_type'])->lockForUpdate()->update(['is_primary'=>false]);return$mediable->mediaAssets()->create($data);},3);}public function setPrimary(MediaAsset $asset):MediaAsset{if(!$asset->exists)throw new InvalidArgumentException('Persisted asset required.');return DB::transaction(function()use($asset){$mediable=$asset->mediable()->firstOrFail();$this->lockMediable($mediable);$mediable->mediaAssetsOfType($asset->asset_type)->lockForUpdate()->update(['is_primary'=>false]);$asset->is_primary=true;$asset->save();return$asset->fresh();},3);}public function deleteRecord(MediaAsset $asset):void{DB::transaction(function()use($asset){if(!$asset->exists)return;$mediable=$asset->mediable()->first();if($mediable)$this->lockMediable($mediable);$asset->delete();},3);}private function lockMediable(Model $model){$model->newQuery()->whereKey($model->getKey())->lockForUpdate()->firstOrFail();}private function validate(array $a){foreach(['asset_type','disk','path'] as $key)if(!isset($a[$key])||trim((string)$a[$key])==='')throw new InvalidArgumentException('Required media field.');if(!in_array($a['asset_type'],MediaAssetType::values(),true))throw new InvalidArgumentException('Invalid asset type.');$path=$a['path'];if(!is_string($path)||$path!==trim($path)||strpos($path,"\0")!==false||preg_match('#^(?:[a-z]+:)?//#i',$path)||preg_match('#^[A-Za-z]:[\\\\/]#',$path)||$path[0]==='/'||$path[0]==='\\')throw new InvalidArgumentException('Path must be relative.');$path=str_replace('\\','/',$path);foreach(explode('/',$path) as $part)if($part===''||$part==='..')throw new InvalidArgumentException('Invalid path segment.');foreach(['width','height'] as $key)if(array_key_exists($key,$a)&&$a[$key]!==null&&(!is_int($a[$key])||$a[$key]<=0))throw new InvalidArgumentException('Invalid dimension.');if(isset($a['file_size'])&&(!is_int($a['file_size'])||$a['file_size']<0))throw new InvalidArgumentException('Invalid file size.');if(isset($a['sort_order'])&&(!is_int($a['sort_order'])||$a['sort_order']<0))throw new InvalidArgumentException('Invalid sort order.');if(array_key_exists('metadata',$a)&&$a['metadata']!==null&&!is_array($a['metadata']))throw new InvalidArgumentException('Invalid metadata.');if(isset($a['is_primary'])&&!is_bool($a['is_primary']))throw new InvalidArgumentException('Invalid primary flag.');return array_merge(['mime_type'=>null,'width'=>null,'height'=>null,'file_size'=>null,'metadata'=>null,'sort_order'=>0,'is_primary'=>false],$a,['path'=>$path]);}}
